			"lightmapFilterEnabled",
			"lightmapFilterRange",
			"lightmapFilterSmoothness",
			"ambientBake",
			"ambientBakeNumSamples",
			"ambientBakeSpherePart",
			"ambientBakeOcclusionBrightness",
			"ambientBakeOcclusionContrast"
